// Define a function called display_extreme_security() that takes two arguments: `action` and `safety`.
fn display_extreme_security(action: &str, safety: i32) {
    // Use an if statement to determine whether the action requires high (1), medium (0), or low (-1) levels of security.
    match safety {
        1 => println!("{} must only be performed under extreme security conditions.", action),
        0 => println!(
            "{} may require some additional precautions but can still be done safely under most circumstances.",
            action
        ),
        -1 => println!("{} should generally not be attempted unless absolutely necessary.", action),
        _ => panic!("Invalid value for 'safety'."),
    }
}

// Call the display_extreme_security() function with appropriate input values.
display_extreme_security("hacking", 1);    // Output: "Hacking must only be performed under extreme security conditions."
display_extreme_security("data analysis", 0); // Output: "Data analysis may require some additional precautions but can still be done safely under most circumstances."
display_extreme_security("skydiving", -1);   // Output: "Skydiving should generally not be attempted unless absolutely necessary."
```
