// Define a struct to hold information about each exercise
struct Exercise {
    name: String,
    sets: i32,
    reps: i32,
    weight: f64,
    date: NaiveDate,
    reliability: f64, // A value between 0 and 1 indicating how reliable the measurement was
}

// Function to calculate the total number of reps performed for an exercise
fn calc_reps(exercise: &Exercise) -> i32 {
    return exercise.sets * exercise.reps;
}

// Function to calculate the total weight lifted for an exercise
fn calc_weight(exercise: &Exercise) -> f64 {
    return exercise.sets as f64 * exercise.repetitions as f64 * exercise.weight;
}

// Function to determine whether an exercise was completed successfully (reliability > threshold)
fn successful_completion(exercise: &Exercise, threshold: f64) -> bool {
    return exercise.reliability >= threshold;
}

// Main function
fn main() {
    let mut exercises = Vec::new();

    // Add some sample exercises
    exercises.push(Exercise {
        name: "Squats".to_string(),
        sets: 5,
        reps: 8,
        weight: 90.0,
        date: NaiveDate::from_ymd(2023, 2, 17),
        reliability: 0.8,
    });
    exercises.push(Exercise {
        name: "Bench Press".to_string(),
        sets: 3,
        reps: 10,
        weight: 100.0,
        date: NaiveDate::from_ymd(2023, 2, 10),
        reliability: 0.6,
    });
    exercises.push(Exercise {
        name: "Deadlifts".to_string(),
        sets: 2,
        reps: 6,
        weight: 120.0,
        date: NaiveDate::from_ymd(2023, 2, 24),
        reliability: 0.9,
    });

    // Calculate the total number of reps and weight lifted for all exercises
    let total_reps = exercises.iter().map(|e| calc_reps(e)).sum::<i32>();
    println!("Total Reps: {}", total_reps);

    let total_weight = exercises.iter().map(|e| calc_weight(e)).sum::<f64>();
    println!("Total Weight Lifted: {:.2}", total_weight);

    // Determine which exercises were successful based on a reliability threshold of 0.7
    let successful_exercises = exercises
        .into_iter()
        .filter(|e| successful_completion(e, 0.7))
        .collect::<Vec<_>>();

   println!("\nSuccessful Exercises:");
    for e in successful_exercises {
        println!(
            "\t{} - {} Sets x {} Reps @ {} lbs ({:.2}%)",
            e.name, e.sets, e.reps, e.weight, e.reliability * 100.0
        );
    }
}
