Here is a sample go program which uses conditional statements (if else) to check whether grade calculation falls under low education criteria or not. The logic is simple - If marks scored by a candidate is less than 50% of total marks i.e., below 25, then the result will be "Failed". Else, if the percentage lies between 51st percentile and 74th percentile inclusive, the result will be "Pass With Distinction", otherwise it'll be "Pass"

 ```go
package main
import(
    "fmt"
)
func main() {

    // Mock input values 
    marks := 38
    totmarks := 90

    // Calculate Percentage
    perc := float64(marks)/float64(totmarks)*100

    fmt.Println("Marks Scored:", marks)
    fmt.Println("Total Marks:", totmarks)
    fmt.Printf("Percentage = %.2f%%\n",perc)

    // Check if mark falls within range [0, 24] -> Fail
    if(marks < int((float64(totmarks)/2))) {
        fmt.Println("Result : Failed")
    } 

    //Check if mark falls within range[50%, 74%] -> Pass with distinction
    elif ((marks >=int((float64(totmarks)/2)) && marks <= int(50+float64(totmarks)*(0.74)))){
        fmt.Println("Result : Passed with Distinction ")
    }

    // All other cases -> pass
    else {
        fmt.Println("Result : Passed")
    }

}
```

