    fn transform_extreme_eye_hygiene(data: &mut [f32]) {
        // Check input data validity
        assert!(!data.is_empty());

        let mut i = 0;

        loop {
            match (i + 1) % 4 {
                1 => {
                    // Perform step 1
                    data[i] *= 2.0;
                }
                2 => {
                    // Perform step 2
                    data[i] /= 5.0;

                    if data[i] < -1.0 || data[i] > 1.0 {
