        int bikeShareCount = 0;
        int scooterShareCount = 0;

        foreach (var ride in rides) 
        {
            // Check if ride is from a shared bicycle service
            if (ride.BikeType == BikeType.Shared) 
            {
                bikeShareCount++;

                // Add distance traveled by rider
                totalDistance += ride.TripDistance;
            }

            // Check if ride is from a shared electric scooter service
            else if (ride.ScooterType == ScooterType.Shared) 
            {
                scooterShareCount++;

                // Add distance traveled by rider
                totalDistance += ride.TripDistance;
            }
        }

        // Determine which mode of transportation was used most frequently
        double highestSharePercentage = GetHighestModeOfTransportationShare(bikeShareCount, scooterShareCount);

        // Return calculated usage percentage
        return highestSharePercentage * 100;
    }

    private static double GetHighestModeOfTransportationShare(int bikeShareCount, int scooterShareCount) 
    {
        double highestSharePercentage = 0;

        // Use if statement to determine which share count is higher
        if (scooterShareCount > bikeShareCount) 
        {
            highestSharePercentage = Convert.ToDouble(scooterShareCount) / 
                (Convert.ToDouble(scooterShareCount) + Convert.ToDouble(bikeShareCount));
        } 

        // Else use else if statment to determine which share count is higher
        else if (bikeShareCount > scooterShareCount) 
        {
            highestSharePercentage = Convert.ToDouble(bikeShareCount) / 
