    int numPeople;
    cin >> numPeople;

    double water = 0.5 * numPeople; // Calculate amount of water needed per person
    double soap = 0.25 * numPeople; // Calculate amount of soap needed per person
    double toothpaste = 0.1 * numPeople; // Calculate amount of toothpaste needed per person
    double towels = numPeople; // Calculate amount of towels needed per person

    // Ask each person whether they want their own set of personal items or share them among everyone
    bool separateItems[numPeople];
    for (int i = 0; i < numPeople; i++) {
        cout << "Person " << i + 1 << ", do you want your own set of personal items (y/n): ";
        char answer;
        cin >> answer;

        if (answer == 'y') {
            separateItems[i] = true;
        } else if (answer == 'n') {
            separateItems[i] = false;
        } else {
            cout << "Invalid input. Please enter y for yes or n for no." << endl;
        }
    }

