    for (int i = 0; i < numPeople; i++) {
        if (!separateItems[i]) {
            water /= numPeople; // Adjust water cost if sharing items
            soap /= numPeople; // Adjust soap cost if sharing items
            toothpaste /= numPeople; // Adjust toothpaste cost if sharing items
        }

        double itemCost = water + soap + toothpaste + towels;
        cout << "Person " << i+1 << ": Total Cost = $" << fixed << setprecision(2) << itemCost << endl;
        totalCost += itemCost; // Add up all item costs
    }

